    "description": "Produces generated load logic for `/docs/[slug]/versions/[version]/+page.ts`.",
    "jsdocRaw": "/**\n * @auto-doc\n * @title Version Detail Load Emitter\n * @group Output\n * Produces generated load logic for `/docs/[slug]/versions/[version]/+page.ts`.\n * @returns TypeScript source for selected version diff data.\n */",
    "signature": "export const createDocsVersionPageTsModule = (): string => {\n\treturn `import { error } from '@sveltejs/kit';\nimport type { PageLoad } from './$types';\nimport { docs, history } from '../../../generated';\n\ntype DiffLine = {\n\tkind: 'context' | 'add' | 'remove';\n\ttext: string;\n};\n\nconst buildUnifiedDiff = (beforeText: string, afterText: string): DiffLine[] => {\n\tconst before = beforeText.split(/\\\\r?\\\\n/);\n\tconst after = afterText.split(/\\\\r?\\\\n/);\n\tconst dp = Array.from({ length: before.length + 1 }, () => Array(after.length + 1).fill(0));\n\n\tfor (let i = before.length - 1; i >= 0; i -= 1) {\n\t\tfor (let j = after.length - 1; j >= 0; j -= 1) {\n\t\t\tdp[i][j] = before[i] === after[j] ? dp[i + 1][j + 1] + 1 : Math.max(dp[i + 1][j], dp[i][j + 1]);\n\t\t}\n\t}\n\n\tconst result: DiffLine[] = [];\n\tlet i = 0;\n\tlet j = 0;\n\n\twhile (i < before.length && j < after.length) {\n\t\tif (before[i] === after[j]) {\n\t\t\tresult.push({ kind: 'context', text: before[i] });\n\t\t\ti += 1;\n\t\t\tj += 1;\n\t\t\tcontinue;\n\t\t}\n\n\t\tif (dp[i + 1][j] >= dp[i][j + 1]) {\n\t\t\tresult.push({ kind: 'remove', text: before[i] });\n\t\t\ti += 1;\n\t\t} else {\n\t\t\tresult.push({ kind: 'add', text: after[j] });\n\t\t\tj += 1;\n\t\t}\n\t}\n\n\twhile (i < before.length) {\n\t\tresult.push({ kind: 'remove', text: before[i] });\n\t\ti += 1;\n\t}\n\n\twhile (j < after.length) {\n\t\tresult.push({ kind: 'add', text: after[j] });\n\t\tj += 1;\n\t}\n\n\treturn result;\n};",
